<?php
declare(strict_types=1);

require dirname(__DIR__) . '/bootstrap.php';
require_method('POST');$admin=require_admin($config);require_csrf();$body=json_body();$userId=(string)($body['user_id']??'');$paidDelta=filter_var($body['paid_seconds_delta']??null,FILTER_VALIDATE_INT);$reason=trim((string)($body['reason']??''));
if(!preg_match('/^[a-f0-9-]{36}$/',$userId)||$paidDelta===false||$paidDelta===0||abs($paidDelta)>360000||mb_strlen($reason)<5||mb_strlen($reason)>200)json_error('VALIDATION_ERROR','Adjustment is invalid.');
$pdo=db($config);
try{$pdo->beginTransaction();expire_credit_lots($pdo,$userId);$stmt=$pdo->prepare('SELECT paid_seconds FROM wallets WHERE user_id=? FOR UPDATE');$stmt->execute([$userId]);$wallet=$stmt->fetch();if(!$wallet)throw new RuntimeException('USER_NOT_FOUND');if((int)$wallet['paid_seconds']+$paidDelta<0)throw new RuntimeException('BALANCE_NEGATIVE');$id=uuid_v4();$pdo->prepare("INSERT INTO credit_ledger (id,user_id,entry_type,paid_delta,reference_type,reference_id,idempotency_key,note) VALUES (?,?,'admin_adjustment',?,'admin',?,?,?)")->execute([$id,$userId,$paidDelta,$admin['id'],'admin:'.$id,$reason]);if($paidDelta>0){if(!grant_credit_lot($pdo,$userId,'paid','admin',$id,$paidDelta,180))throw new RuntimeException('CREDIT_LOT_FAILED');}else{if(remove_paid_lots($pdo,$userId,-$paidDelta)!==-$paidDelta)throw new RuntimeException('BALANCE_NEGATIVE');}audit_admin($config,$admin['id'],'balance.adjust','user',$userId);$pdo->commit();json_response(['ok'=>true,'paid_seconds'=>(int)$wallet['paid_seconds']+$paidDelta]);}catch(Throwable $error){if($pdo->inTransaction())$pdo->rollBack();$code=$error->getMessage();if(in_array($code,['USER_NOT_FOUND','BALANCE_NEGATIVE'],true))json_error($code,'Adjustment could not be applied.',409);error_log('admin adjustment failed: '.$error->getMessage());json_error('INTERNAL_ERROR','Adjustment could not be applied.',500);}
